/// @dev precondition - the caller must have the DEFAULT_ADMIN_ROLE.
/// @param auction The address of the auction contract.
function setAuction(
  address auction
) external onlyRole(DEFAULT_ADMIN_ROLE) {
  _setAuction(auction);
}

